update setmeal
name = #{name}, category_id = #{categoryId}, price = #{price}, image = #{image}, description = #{description}, status = #{status}, update_time = #{updateTime}, update_user = #{updateUser},
where id = #{id}

mapper.select:
select s.id, s.name, s.category_id, s.price, s.image, s.description, s.status, s.create_time, s.update_time, s.create_user, s.update_user, c.name as categoryName from setmeal s left join category c on s.category_id = c.id
and s.name like concat('%', #{name}, '%')
and s.category_id = #{categoryId}
and s.status = #{status}
order by s.create_time desc

